/********************************************************************************
 * ì¤ëª : Page Load ì´ë²¤í¸
 ********************************************************************************/
scwin.onpageload = function() {
    // Main Contents WFrameììë ìì´ë ì¤ë³µì²´í¬ë¥¼ í´ì íë¤.
    wfm_container.options._idCollisionCheck = false;

    // ë©ì¸ íì´ì§ì¼ ê²½ì° Navigation + Header ì ë³´ë¥¼ ë¸ì¶íì§ ìëë¤.
    scwin.setNavitionVisible();

    // í¼ë¸ë¦¬ì± ìì
    // ì¹ì ê·¼ì±(ì¤í¬ë¦° ë¦¬ëê¸°)-  aíê·¸(class="skip-nav" ë³¸ë¬¸ìì­ ë°ë¡ê°ê¸°)ì href="#fs_content"ë¥¼ ë³¸ë¬¸ìì­(class="container-layout")ì ìì´ëì ì°ê²°
    const cntLayout = document.querySelector(".portal > .container-layout");
    cntLayout.setAttribute("id", "fs_content");

    dlMenuM.set('infoSysCd', com.gfnGetInfoSysCd());

    // ë©ì¸ íì´ì§ ë¡ë ì¬ë¶
    _gcm.Global.setMainLoaded(true);

    // ìµì´ íì´ì§ í¸ì¶ ì menuCangVal ê°ì´ ìì ê²½ì° í´ë¹ íì´ì§ë¡ ì´ë í ë ì´ììì ì¨ê¸´ë¤
    let result = false;

    if (!comUtil.gfnIsEmpty(WebSquareExternal.menuCangVal)) {
        let option = null;

        if (!comUtil.gfnIsEmpty(WebSquareExternal.param)) {
            Object.keys(WebSquareExternal.param).forEach(key => {
                if (comUtil.gfnIsArray(WebSquareExternal.param[key])) {
                    WebSquareExternal.param[key] = WebSquareExternal.param[key][0];
                }
            });

            option = { param : WebSquareExternal.param };
        }

        result = com.gfnInitMovePage(WebSquareExternal.menuCangVal, WebSquareExternal.target, option);

        if (!comUtil.gfnIsEmpty(WebSquareExternal.param.externalYn) && WebSquareExternal.param.externalYn !== "Y") {
            if (document.referrer !== "" && $p.parent() !== WebSquare.util.getMainFrame()) {
                // ë§í¬ë¡ ìì°½ì´ ì´ë¦° ê²½ì° window.opener = null ì²ë¦¬íë¤.
                window.opener = null;
            }
        }

        if (WebSquareExternal.menuCangVal === _gcm.Global.getLoginMenuCangVal()) {
            history.replaceState({}, "", "/");
        }
    } else {
        if ($p.parent() !== WebSquare.util.getMainFrame()) {
            // í¹ì  íì´ì§ë¡ ì´ëíì§ ìë ê²½ì° window.opener = null ì²ë¦¬íë¤.
            window.opener = null;
        }
    }

    // í¬íê¸°ë¥ ì¡°íí¸ì¶
    scwin.fnSrchPrtlFtreMainList().then(rtn => {
        if (!result) {
            // ë©ì¸ íì´ì§ ë¡ë
            const dev_goto_menuId = WebSquare.localStorage.getItem("dev_goto_menuId");
            const menuInfo = _gcm.Global.getMenuDataList().getAllJSON().filter(f => f.menuCangVal === dev_goto_menuId);
            if (( comUtil.gfnIsNotEmpty(com.gfnGetUsrInfo())) &&  ( !comUtil.gfnIsEmpty(dev_goto_menuId) && comUtil.gfnGetThisMenuCangVal() != dev_goto_menuId)
            && !( menuInfo.length === 0 || comUtil.gfnIsEmpty(menuInfo[0].menuCangVal) || comUtil.gfnIsEmpty(menuInfo[0].scrnSrcePathNm))) {
                com.gfnOpenMenu(dev_goto_menuId);
            } else {
                com.gfnOpenMenu(_gcm.Global.getMainMenuCangVal());
            }
        }
    });
};

/********************************************************************************
 * ì¤ëª : ë©ì¸ íì´ì§ì¼ ê²½ì° Navigation + Header ì ë³´ë¥¼ ë¸ì¶íì§ ìëë¤.
