scwin.setNavitionVisible = function(menuCangVal = com.gfnGetMenuCangVal()) {
    // í¼ë¸ë¦¬ì± ìì - í¼ë¸ë¦¬ì± ìì - ë©ì¸íë©´ ë¸ì¶ëë íë©´ìì ìµìì ê·¸ë£¹ .portalì í´ëì¤ ì¶ê°, ì­ì íì¬ ë°°ê²½ìì ëìì¸ ë³ê²½
    const portalElement = window.document.querySelector(".portal");
    const callUrl = window.location.href;
    if(
        (callUrl.indexOf("link") > -1 && callUrl.indexOf("PBPA021_01") > -1 && callUrl.indexOf("single") > -1 && callUrl.indexOf("encryptParam") > -1) // í¬ì°°ë³´ê¸°
        || (callUrl.indexOf("link") > -1 && callUrl.indexOf("FUUA017_01") > -1 && callUrl.indexOf("single") > -1 ) // ì¸ì¦ì¼í°
        || (callUrl.indexOf("link") > -1 && callUrl.indexOf("PNPE027_01") > -1 && callUrl.indexOf("bidPbancNo") > -1 && callUrl.indexOf("bidPbancOrd") > -1 && callUrl.indexOf("pbancType") > -1 && callUrl.indexOf("single") > -1 ) // ìì°°ìì¸
        || (
            callUrl.indexOf("link") > -1 && callUrl.indexOf("FIUA027_01") > -1 && callUrl.indexOf("oderPlanNo") > -1 && callUrl.indexOf("ctrtDmndRcptNo") > -1 && callUrl.indexOf("ctrtDmndRcptOrd") > -1
           && callUrl.indexOf("bidPbancNo") > -1 && callUrl.indexOf("bfSpecRegNo") > -1 && callUrl.indexOf("bidPbancOrd") > -1 && callUrl.indexOf("scsbdMthdCd") > -1 && callUrl.indexOf("bidPrgrsOrd") > -1
           && callUrl.indexOf("bidClsfNo") > -1 && callUrl.indexOf("bidPgst") > -1 && callUrl.indexOf("ctrtNo") > -1 && callUrl.indexOf("ctrtChgOrd") > -1 && callUrl.indexOf("untyInspIgiNo") > -1
           && callUrl.indexOf("untyPyprNo") > -1 && callUrl.indexOf("prcmBsneSeCd") > -1 && callUrl.indexOf("dlvdmRcptDt") > -1 && callUrl.indexOf("dlvdmRcptNo") > -1 && callUrl.indexOf("dlreqDt") > -1
           && callUrl.indexOf("dlreqNo") > -1 && callUrl.indexOf("dlvdmReqYn") > -1 && callUrl.indexOf("dlreqChgOrd") > -1 && callUrl.indexOf("srchName") > -1 && callUrl.indexOf("single") > -1
        ) // ëª¨ë°ì¼íµí©ê²ì
    ){
        portalElement.classList.add("bid-gnb_head");
    }

    if (!comUtil.gfnIsEmpty(_gcm.Global.getMenuDataList())) {
        // ë©ì¸ íì´ì§ì¼ ê²½ì° Navigation + Header ì ë³´ë¥¼ ë¸ì¶íì§ ìëë¤.
        if (menuCangVal === _gcm.Global.getMainMenuCangVal() && com.gfnGetContxtSeCd() !== "ì½010012") {
            (!wfm_navigation.hasClass("hide")) && wfm_navigation.addClass("hide");
            (!wfm_cntsHeader.hasClass("hide")) && wfm_cntsHeader.addClass("hide");
            //portalElement.parentElement.classList.add("has-main");
            //portalElement.parentElement.classList.remove("has-main");
        } else {
            (wfm_navigation.hasClass("hide")) && wfm_navigation.removeClass("hide");
            (wfm_cntsHeader.hasClass("hide")) && wfm_cntsHeader.removeClass("hide");
            portalElement.parentElement.classList.remove("has-main");
        }
    }
};



