/********************************************************************************
 * ì¤ëª : fingerprinting ëª¨ë í¸ì¶
 ********************************************************************************/
scwin.fnSetFingerPrinting = async function() {
    //console.log("Call FingerPrinting!!");

    // fingerprinting ê´ë ¨ ì½ë
    let fpUtil = scwin.fpUtil();
    let osInfo = fpUtil.getOSInfo();
    let brInfo = fpUtil.getBrowserInfo();
    let screenInfo = fpUtil.getScreenInfo();
    let strWebglFP = fpUtil.webglFingerPrinting();
    let strCanFP = fpUtil.canvasFingerPrinting();
    let strTimezone = fpUtil.getTimeZone();
    let strDeviceFP = fpUtil.deviceFingerPrinting();

    dlFpParamM.set("osNameVal", osInfo.OSName);
    dlFpParamM.set("osFlatformVal", osInfo.OSFlatform);
    dlFpParamM.set("cpuNo", osInfo.cpu);
    dlFpParamM.set("memorySize", osInfo.memory);
    dlFpParamM.set("browserName", brInfo.browserName);
    dlFpParamM.set("browserVersion", brInfo.browserVersion);
    dlFpParamM.set("browserFlatform", brInfo.browserFlatform);
    dlFpParamM.set("screenWidth", screenInfo.screenWidth);
    dlFpParamM.set("screenHeight", screenInfo.screenHeight);
    dlFpParamM.set("screenDepth", screenInfo.screenDepth);
    dlFpParamM.set("timeZone", strTimezone);
    dlFpParamM.set("canvasFingerPrint", strCanFP.hash);
    dlFpParamM.set("webglFingerPrint", strWebglFP.hash);
    dlFpParamM.set("deviceFingerPrint", strDeviceFP.hash);
    dlFpParamM.set("userAgentVal", window.navigator.userAgent);

    try {
        let sbmOption = {
            id: "fingerPrint",
            action: "/ts/tsa/tsae/fingerPrint.do",
            inData: "dlFpParamM",
            outData: "dlResultM",
            msgYn: {
                succ: false,
                err: true
            },
        };

        com.gfnExecute(sbmOption).then((rtn) => {
            if (dlResultM.get('resultCd') == '0000') {
                //alert("ì ìì²ë¦¬ëììµëë¤.");
                return true;
            } else {
                //alert("ì ì¥ì ì¤ë¥ê° ë°ìíììµëë¤. ë¤ì ìë ë¶íëë¦½ëë¤.");
                return false;
            }
        });

    } catch (e) {
        //alert("ì ì¥ì ì¤ë¥ê° ë°ìíììµëë¤. ë¤ì ìë ë¶íëë¦½ëë¤.");
        console.error(e);
    }
};

/********************************************************************************
 * ì¤ëª : fingerprinting ëª¨ë
 ********************************************************************************/
scwin.fpUtil = function (e) {
    const fpUtil = {
        getOSInfo: function () {
            const useragent = window.navigator.userAgent.toLowerCase();
            let useragentArray = useragent.split("(").join().split(")");
            let osInfoArray = useragentArray[0].split(",")[1].split(";");

            let strDeviceOS = fpUtil.nameDeviceOS(osInfoArray[0].trim());
            let strDeviceBits = fpUtil.nameFlatform(osInfoArray[2].trim());

            let cpuCore = window.navigator.hardwareConcurrency;
            let memoryCore = window.navigator.deviceMemory;
            return {
                OSName: strDeviceOS,
                OSFlatform: strDeviceBits,
                cpu: cpuCore,
                memory: memoryCore
            };
        },
        getBrowserInfo: function () {
            let struseragent = window.navigator.userAgent.toLowerCase();
            let offsetBrowser;
            let browserName = "";
            let browserVersion = "";
            if ((offsetBrowser = struseragent.indexOf("edge")) != -1) {
                browserName = "Edge";
            } else if ((offsetBrowser = struseragent.indexOf("edg/")) != -1) {
                browserName = "Edge";
            } else if ((offsetBrowser = struseragent.indexOf("opr")) != -1) {
                browserName = "Opera";
            } else if ((offsetBrowser = struseragent.indexOf("chrome")) != -1) {
                browserName = "Chrome";
            } else if ((offsetBrowser = struseragent.indexOf("trident")) != -1) {
                browserName = "MS IE";
            } else if ((offsetBrowser = struseragent.indexOf("firefox")) != -1) {
                browserName = "Mozilla Firefox";
            } else if ((offsetBrowser = struseragent.indexOf("safari")) != -1) {
                browserName = "Safari";
            } else {
                browserName = "Other";
                browserVersion = "";
            }
            if (offsetBrowser != -1) {
                browserVersion = struseragent.substring(offsetBrowser);
                browserVersion = browserVersion.split(" ")[0].split("/")[1];
            }

            const userBroswerplatform = window.navigator.platform.toLowerCase();
            let strBroswerBits = fpUtil.nameFlatform(userBroswerplatform.trim());

            return {
                browserName: browserName,
                browserVersion: browserVersion,
                browserFlatform: strBroswerBits
            };
        },
        getScreenInfo: function () {
            const screenHeight = window.screen.height;
            const screenWidth = window.screen.width;
            const screenDepth = window.screen.colorDepth

            const browserHeight = window.innerHeight;
            const browserWidth = window.innerWidth;

            return {
                screenWidth: screenWidth,
                screenHeight: screenHeight,
                screenDepth: screenDepth,
                browserWidth: browserWidth,
                browserHeight: browserHeight
            };
        },
        getTimeZone: function () {
            try {
                return new Date().getTimezoneOffset();
            } catch (err) {
                return "";
            }
        },
        nameDeviceOS: function (osCode) {
            let osName = "";
            if (osCode.indexOf("windows") != -1) {
                if (osCode.indexOf("windows nt 10.0") != -1) {
                    majorPV = fpUtil.isWindows11();
                    if (majorPV == true)
                        osName = "Windows 11";
                    else
                        osName = "Windows 10";
                }
                // else if(osCode.indexOf("windows nt 10.0") != -1)     osName="Windows 10";
                else if (osCode.indexOf("windows nt 6.3") != -1) osName = "Windows 8.1";
                else if (osCode.indexOf("windows nt 6.2") != -1) osName = "Windows 8";
                else if (osCode.indexOf("windows nt 6.1") != -1) osName = "Windows 7";
                else if (osCode.indexOf("windows nt 6.0") != -1) osName = "Windows Vista";
                else if (osCode.indexOf("windows nt 5.1") != -1) osName = "Windows XP";
                else if (osCode.indexOf("windows nt 5.0") != -1) osName = "Windows Vista";
                else osName = "Windows(" + osCode + ")";
            } else if (osCode.indexOf("mac") !== -1) {
                if (osCode.indexOf("mac os x beta") !== -1) osName = "Mac OSX Beta (Kodiak)";
                else if (osCode.indexOf("mac os x 10.0") !== -1) osName = "Mac OSX Cheetah";
                else if (osCode.indexOf("mac os x 10.1") !== -1) osName = "Mac OSX Puma";
                else if (osCode.indexOf("mac os x 10.2") !== -1) osName = "Mac OSX Jaguar";
                else if (osCode.indexOf("mac os x 10.3") !== -1) osName = "Mac OSX Panther";
                else if (osCode.indexOf("mac os x 10.4") !== -1) osName = "Mac OSX Tiger";
                else if (osCode.indexOf("mac os x 10.5") !== -1) osName = "Mac OSX Leopard";
                else if (osCode.indexOf("mac os x 10.6") !== -1) osName = "Mac OSX Snow Leopard";
                else if (osCode.indexOf("mac os x 10.7") !== -1) osName = "Mac OSX Lion";
                else if (osCode.indexOf("mac os x 10.8") !== -1) osName = "Mac OSX Mountain Lion";
                else if (osCode.indexOf("mac os x 10.9") !== -1) osName = "Mac OSX Mavericks";
                else if (osCode.indexOf("mac os x") !== -1) osName = "Mac OSX (Version Unknown)";
                else osName = "Mac OS (Unknown)";
            } else if (osCode.indexOf("ipad") !== -1) {
                osName = "iPad";
            } else if (osCode.indexOf("ipod") !== -1) {
                osName = "iPod";
            } else if (osCode.indexOf("iphone") !== -1) {
                osName = "iPhone";
            } else if (osCode.indexOf("X11") != -1) {
                osName = "UNIX";
            } else if (osCode.indexOf("sunos") !== -1) {
                osName = "Sun OS";
            } else if (osCode.indexOf("Android") != -1) {
                osName = fpUtil.getAndroidName();
            } else if (osCode.indexOf("linux") != -1) {
                if (osCode.indexOf("ubuntu") !== -1) osName = "Ubuntu";
                else osName = "Linux";
            } else {
                osName = "Unknown";
            }
            return osName;
        },
        getAndroidName: function () {
            let useragent = window.navigator.userAgent;
            let regex = /Android (.*);.*;\s*(.*)\sBuild/;
            let regResult = regex.exec(useragent);

            let deviceName = "Android";
            if (regResult) {
                let devVersion = regResult[1];
                let devName = regResult[2];
                deviceName += " " + devVersion + " " + devName;
            }
            else {
                deviceName += "(Unknown)";
            }
            return deviceName;
        },
        nameFlatform: function (osBitData) {
            let osbits = "";

            if (osBitData.indexOf("x64") !== -1) {
                osbits = "64";
            } else if (osBitData.indexOf("x32") !== -1) {
                osbits = "32";
            } else if (osBitData.indexOf("wow64") !== -1) {
                osbits = "64";
            } else if (osBitData.indexOf("win64") !== -1) {
                osbits = "64";
            } else if (osBitData.indexOf("win32") !== -1) {
                osbits = "32";
            } else if (osBitData.indexOf("x86") !== -1) {
                osbits = "32";
            } else if (osBitData.indexOf("ppc") !== -1) {
                osbits = "64";
            } else if (osBitData.indexOf("alpha") !== -1) {
                osbits = "64";
            } else if (osBitData.indexOf("68k") !== -1) {
                osbits = "64";
            } else if (osBitData.indexOf("iphone") !== -1) {
                osbits = "32";
            } else if (osBitData.indexOf("android") !== -1) {
                osbits = "32";
            } else {
                osbits = "Unknown";
            }

            return osbits;
        },
        deviceFingerPrinting: function () {
            let osInfo = fpUtil.getOSInfo();
            let brInfo = fpUtil.getBrowserInfo();
            let screenInfo = fpUtil.getScreenInfo();
            let timezoneInfo = fpUtil.getTimeZone();
            //let dntYn = window.navigator.doNotTrack;
            let cookiYn = window.navigator.cookieEnabled;

            let deviceInfo = osInfo.OSName + osInfo.OSFlatform + osInfo.cpu + osInfo.memory +
                brInfo.browserName + brInfo.browserFlatform +
                screenInfo.screenWidth + screenInfo.screenHeight + screenInfo.screenDepth +
                timezoneInfo + cookiYn;


            return {
                raw: deviceInfo,
                hash: sha256(deviceInfo)
            }
        },
        canvasFingerPrinting: function () {
            var canvas = document.createElement('canvas');
            var ctx = canvas.getContext('2d');
            canvas.height = 30;
            canvas.width = 500;

            //U+1F603 ì´ëª¨ì§ SMILING FACE : OSë³ë¡ ê·¸ë¦¼ì´ ë¤ë¥´ê² ëì´
            var txt = "ì°¨ì¸ë ëë¼ì¥í° íë¡ì í¸ 2023 &#128512; &lt;canvas&gt; 1.0 &#128512;";
            ctx.textBaseline = "top";
            // The most common type
            ctx.font = "16px 'Arial'";
            ctx.textBaseline = "alphabetic";
            ctx.fillStyle = "#f60";
            ctx.fillRect(125, 1, 62, 20);

            ctx.fillStyle = "#069";
            ctx.fillText(txt, 2, 15);
            ctx.fillStyle = "rgba(102, 204, 0, 0.7)";
            ctx.fillText(txt, 4, 17);

            ctx.globalCompositeOperation = "multiply";
            ctx.fillStyle = "rgb(240,1,255)";
            ctx.beginPath();
            ctx.arc(50, 50, 50, 0, Math.PI * 2, true);
            ctx.closePath();
            ctx.fill();

            var strCanvasFingerPrinting = canvas.toDataURL();

            return {
                data: strCanvasFingerPrinting,
                hash: sha256(strCanvasFingerPrinting)
            };
        },

        webglFingerPrinting: function () {
            var canvas, ctx, width = 256, height = 128;
            canvas = document.createElement("canvas");

            canvas.width = width, canvas.height = height, ctx = canvas
                .getContext("webgl2")
                || canvas.getContext("experimental-webgl2")
                || canvas.getContext("webgl")
                || canvas.getContext("experimental-webgl")
                || canvas.getContext("moz-webgl");

            try {
                let f = "attribute vec2 attrVertex;varying vec2 varyinTexCoordinate;uniform vec2 uniformOffset;void main(){varyinTexCoordinate=attrVertex+uniformOffset;gl_Position=vec4(attrVertex,0,1);}";
                let g = "precision mediump float;varying vec2 varyinTexCoordinate;void main() {gl_FragColor=vec4(varyinTexCoordinate,0,1);}";
                let h = ctx.createBuffer();

                ctx.bindBuffer(ctx.ARRAY_BUFFER, h);

                let i = new Float32Array([-.2, -.9, 0, .4, -.26, 0, 0, .7321, 0]);

                ctx.bufferData(ctx.ARRAY_BUFFER, i, ctx.STATIC_DRAW),
                    h.itemSize = 3, h.numItems = 3;

                let j = ctx.createProgram();
                let k = ctx.createShader(ctx.VERTEX_SHADER);

                ctx.shaderSource(k, f);
                ctx.compileShader(k);

                let l = ctx.createShader(ctx.FRAGMENT_SHADER);

                ctx.shaderSource(l, g);
                ctx.compileShader(l);
                ctx.attachShader(j, k);
                ctx.attachShader(j, l);
                ctx.linkProgram(j);
                ctx.useProgram(j);

                j.vertexPosAttrib = ctx.getAttribLocation(j, "attrVertex");
                j.offsetUniform = ctx.getUniformLocation(j, "uniformOffset");

                ctx.enableVertexAttribArray(j.vertexPosArray);
                ctx.vertexAttribPointer(j.vertexPosAttrib, h.itemSize, ctx.FLOAT,
                    !1, 0, 0);
                ctx.uniform2f(j.offsetUniform, 1, 1);
                ctx.drawArrays(ctx.TRIANGLE_STRIP, 0, h.numItems);

            } catch (e) {
            }
            let m = "";
            let n = new Uint8Array(width * height * 4);
            ctx.readPixels(0, 0, width, height, ctx.RGBA, ctx.UNSIGNED_BYTE, n);
            m = JSON.stringify(n).replace(/,?"[0-9]+":/g, "");
            //      document.body.appendChild(document.createElement('br'));
            //      document.body.appendChild(document.createTextNode(sha256(m)));
            return {
                raw: m,
                data: ctx.canvas.toDataURL(),
                hash: sha256(m)
            }
        },
        isWindows11: async function () {
            try {
                let majorPV = await window.navigator.userAgentData.getHighEntroopyValues(["platformVersion"]).then(function (uapv) {
                    let winver = Number(uapv.platformVersion.split('.')[0]);
                    if (winver > 10)
                        return true;
                    else
                        return false;

                });
            } catch (e) {
                return false;
            }
        }
    };

    var sha256 = (function () {
        let i = 1,
            j,
            K = [],
            H = [];
        while (++i < 18) {
            for (j = i * i; j < 312; j += i) {
                K[j] = 1;
            }
        }
        function x(num, root) {
            return (Math.pow(num, 1 / root) % 1) * 4294967296 | 0;
        }
        for (i = 1, j = 0; i < 313;) {
            if (!K[++i]) {
                H[j] = x(i, 2);
                K[j++] = x(i, 3);
            }
        }
        function S(X, n) { return (X >>> n) | (X << (32 - n)); }
        function SHA256(b) {
            let HASH = H.slice(i = 0),
                s = unescape(encodeURI(b)), /* encode as utf8 */
                W = [],
                l = s.length,
                m = [],
                a, y, z;
            for (; i < l;) m[i >> 2] |= (s.charCodeAt(i) & 0xff) << 8 * (3 - i++ % 4);
            l *= 8;
            m[l >> 5] |= 0x80 << (24 - l % 32);
            m[z = (l + 64 >> 5) | 15] = l;
            for (i = 0; i < z; i += 16) {
                a = HASH.slice(j = 0, 8);
                for (; j < 64; a[4] += y) {
                    if (j < 16) {
                        W[j] = m[j + i];
                    } else {
                        W[j] =
                            (S(y = W[j - 2], 17) ^ S(y, 19) ^ (y >>> 10)) +
                            (W[j - 7] | 0) +
                            (S(y = W[j - 15], 7) ^ S(y, 18) ^ (y >>> 3)) +
                            (W[j - 16] | 0);
                    }
                    a.unshift(
                        (
                            y = (
                                a.pop() +
                                (S(b = a[4], 6) ^ S(b, 11) ^ S(b, 25)) +
                                (((b & a[5]) ^ ((~b) & a[6])) + K[j]) | 0
                            ) +
                            (W[j++] | 0)
                        ) +
                        (S(l = a[0], 2) ^ S(l, 13) ^ S(l, 22)) +
                        ((l & a[1]) ^ (a[1] & a[2]) ^ (a[2] & l))
                    );
                }
                for (j = 8; j--;) HASH[j] = a[j] + HASH[j];
            }
            for (s = ''; j < 63;) s += ((HASH[++j >> 3] >> 4 * (7 - j % 8)) & 15).toString(16);
            return s;
        }
        return SHA256;
    })();

    return fpUtil;
};

