/********************************************************************************
 * ì¤ëª : íìë¡ë ì°¾ê¸°
 ********************************************************************************/
scwin.fnMatchedPathPrtlFtreNo = function(prtlFtreNo, pathPrtlFtreNo){
    try {
        if( comUtil.gfnIsEmpty(prtlFtreNo) || comUtil.gfnIsEmpty(pathPrtlFtreNo) ) {
            return false;
        }
        let pathPrtlFtreNoArr = pathPrtlFtreNo.split("/");
        for(let i = 0; i<pathPrtlFtreNoArr.length; i++){
            let tempPrtlFtreNo = pathPrtlFtreNoArr[i].replace(/[^0-9]/g, '');
            if( prtlFtreNo === tempPrtlFtreNo) return true;
        }
        return false;
    } catch (e) {
        console.error(e);
    }
}

/********************************************************************************
 * ì¤ëª : í¬íê¸°ë¥ íë©´ Open í¨ì
 ********************************************************************************/
scwin.fnOpenPortal = function(prtlFtreNo, opt){
    try {
        let width = opt?.width || 1000;
        let height = opt?.height || 1000;
        let callback = opt?.callback || "";
        if(prtlFtreNo == "01094") {
            width = opt?.width || 1450;
            height = opt?.height || 800;
        }
        if( comUtil.gfnIsEmpty(prtlFtreNo)) {
            return false;
        }

        let json = dlPrtlFtreL.getMatchedJSON("prtlFtreNo", prtlFtreNo, true);
        if( comUtil.gfnIsEmpty(json) || json.length !== 1 ) {
            return false;
        }

        let prtlFtreNm = json[0].prtlFtreNm;
        let upPrtlFtreNo = json[0].upPrtlFtreNo;
        let lnkUrl = json[0].scrnUrl; // ë§í¬URL
        let menuCangVal = json[0].menuCangVal; // ë©ë´í¸ì¶ê°
        let scrnUrl = json[0].scrnUrl; // íë©´ê²½ë¡
        let indtYn = json[0].indtYn; // íìì¬ë¶
        let isleafYn = json[0].isleafYn; // ìµíìì¬ë¶
        let extlDomnYn = json[0].extlDomnYn; // ì¸ë¶ëë©ì¸ì¬ë¶
        let popupUseYn = json[0].popupUseYn; // íìì¬ì©ì¬ë¶
        let banrIndtYn = json[0].popupUseYn; // ë°°ëíìì¬ë¶
        let untyAtchFileNo = json[0].popupUseYn; // íµí©ì²¨ë¶íì¼ë²í¸

        let prtlFtreCn = json[0].prtlFtreCn; // í¬íê¸°ë¥ë´ì©
        let cangParmVal = json[0].cangParmVal; // í¸ì¶íë¼ë¯¸í°ê°

        if( comUtil.gfnIsEmpty(lnkUrl) && comUtil.gfnIsEmpty(menuCangVal)) {
            return false;
        }

        if( extlDomnYn === "Y"){

            const httpsExp = new RegExp(/^https:?/);
            const httpExp = new RegExp(/^http:?/);

            if( !httpsExp.test(lnkUrl) && !httpExp.test(lnkUrl) ){
                if( lnkUrl.substring(0,0) === "/" )   {
                    //return;
                }
            }

            if(popupUseYn === "Y" ){
                let pOption = "width="    + width
                            + ", height=" + height
                            + ", left="   + (screen.width - width) / 2
                            + ", top="    + (screen.height - height) / 2;

                window.open(lnkUrl, prtlFtreNm, pOption);
            }else{
                // window ìí­ì¼ë¡ ì´ê¸°
                comUtil.gfnOpenNewTab(lnkUrl);
            }
        }else{
            let paramObj = {};

            if( !comUtil.gfnIsEmpty(cangParmVal) ){
                try{
                    paramObj = JSON.parse(cangParmVal);
                }catch (e) {
                    console.error(e);
                }
            }

            if(popupUseYn === "Y" ){
                com.gfnOpenPopup(
                    {
                    menuCangVal: menuCangVal, // íìì°½ ìì´ë
                    popupId: menuCangVal,
                    popupName: prtlFtreNm,
                    param: paramObj,
                    width: width, // ê°ë¡ ì¬ì´ì¦
                    height: height, // ì¸ë¡ ì¬ì´ì¦
                    //callbackFn: "scwin.fnCallbackBsneClsfPoup" // ì½ë°± í¨ì ì¤í
                    callbackFn: callback // ì½ë°± í¨ì ì¤í
                    }
                );
            }else{
                let option =  {
                    isHistory: true,
                    param: paramObj,
                    //targetMain: true,
                    //targetTab: false,
                };
                com.gfnOpenMenu(menuCangVal, option);  // ë©ë´í¸ì¶
            }
        }
    } catch (e) {
        console.error(e);
    }
};
